        boolean[] isPrime = new boolean[n + 1];
        Arrays.fill(isPrime, true);
        isPrime[0] = false;
        isPrime[1] = false;
        for (int i = 2; i * i <= n; i++) {
            if (isPrime[i]) {
                for (int j = i * i; j <= n; j += i) {
                    isPrime[j] = false;
                }
            }
        }

        int primeCount = 0;
        for (int i = 2; i <= n; i++) {
            if (isPrime[i]) primeCount++;
        }
        int compositeCount = n - primeCount;

        long res = 1;
        int MOD = 1000000007;
        for (int i = 1; i <= primeCount; i++) {
            res = res * i % MOD;
        }
        for (int i = 1; i <= compositeCount; i++) {
            res = res * i % MOD;
        }
        return (int) res;
    }
}

