    public String alphabetBoardPath(String target) {
        int x = 0, y = 0;
        StringBuilder sb = new StringBuilder();

        for (char c : target.toCharArray()) {
            int dx = (c - 'a') / 5;
            int dy = (c - 'a') % 5;

            // Move up
            while (x > dx) {
                sb.append('U');
                x--;
            }

            // Move left
            while (y > dy) {
                sb.append('L');
                y--;
            }

            // Move down
            while (x < dx) {
                sb.append('D');
                x++;
            }

            // Move right
            while (y < dy) {
                sb.append('R');
                y++;
            }

            sb.append('!');
        }
        return sb.toString();
    }
