    }

    private int minRemovals(int[] arr, int i, int j, int[][] dp) {
        if (i > j) return 0;
        if (i == j) return 1;
        if (dp[i][j] != -1) return dp[i][j];

        int ans = minRemovals(arr, i + 1, j, dp) + 1;
        for (int k = i + 1; k <= j; k++) {
            if (arr[i] == arr[k])
                ans = Math.min(ans, minRemovals(arr, i + 1, k - 1, dp) + minRemovals(arr, k + 1, j, dp));
        }
        return dp[i][j] = ans;
    }
}

