public class Solution {
    public int closestToTarget(int[] arr, int target) {
        int minDiff = Integer.MAX_VALUE;
        Set<Integer> prefix = new HashSet<>();

        for (int n : arr) {
            Set<Integer> nextPrefix = computeNextPrefix(prefix, n);
            updateMinDifference(minDiff, nextPrefix, target);

            prefix = nextPrefix;
        }
        return minDiff;
    }

    private Set<Integer> computeNextPrefix(Set<Integer> prefix, int n) {
        Set<Integer> nextPrefix = new HashSet<>();
        for (int p : prefix) {
            nextPrefix.add(p & n);
        }
        nextPrefix.add(n);
        return nextPrefix;
    }

    private void updateMinDifference(int minDiff, Set<Integer> nextPrefix, int target) {
        for (int p : nextPrefix) {
            minDiff = Math.min(minDiff, Math.abs(p - target));
        }
    }
}

