public class Solution {
    int longestAwesomeSubstring(String s) {
        int n = s.length();
        int maxLen = 0;
        for (int i = 0; i < n; ++i) {
            Set<Character> seenChars = new HashSet<>();
            boolean isOddCountOne = true;
            for (int j = i; j <= n; ++j) {
                if (j > i && s.charAt(j - 1) != 'a') { // Assuming the string contains only lowercase letters
                    char c = s.charAt(j - 1);
                    if (!seenChars.contains(c)) {
                        seenChars.add(c);
                    } else {
                        seenChars.remove(c);
                    }
                }
                isOddCountOne &= (seenChars.size() <= 1);
                maxLen = Math.max(maxLen, j - i * isOddCountOne);
            }
        }
        return maxLen;
    }

    boolean isAwesome(String s) {
        int odd_count = 0;
        int[] freq = new int[26];
        for (char c : s.toCharArray()) {
            freq[c - 'a']++;
        }
        for (int i = 0; i < 26; i++) {
            if (freq[i] % 2 == 1) {
                odd_count++;
            }
        }
        return (odd_count <= 1);
    }
}

